## Secure Implementation

### **Option 1: Strict Validation (Recommended)**

```javascript
const path = require('path');
const fs = require('fs').promises;

app.get('/api/file', async (req, res) => {
  try {
    const filename = req.query.name;

    // 1. Input validation
    if (!filename || typeof filename !== 'string') {
      return res.status(400).json({ error: 'Invalid filename' });
    }

    // 2. Sanitize: Remove any path traversal attempts
    const sanitized = path.basename(filename);

    // 3. Whitelist allowed extensions
    const allowedExtensions = ['.pdf', '.jpg', '.png', '.txt'];
    const ext = path.extname(sanitized).toLowerCase();
    if (!allowedExtensions.includes(ext)) {
      return res.status(403).json({ error: 'File type not allowed' });
    }

    // 4. Construct safe path
    const uploadsDir = path.join(__dirname, 'uploads');
    const filepath = path.join(uploadsDir, sanitized);

    // 5. Verify the resolved path is within uploads directory
    const realPath = await fs.realpath(filepath).catch(() => null);
    if (!realPath || !realPath.startsWith(uploadsDir)) {
      return res.status(403).json({ error: 'Access denied' });
    }

    // 6. Check file exists and is a file (not directory)
    const stats = await fs.stat(realPath);
    if (!stats.isFile()) {
      return res.status(404).json({ error: 'File not found' });
    }

    // 7. Send file with proper headers
    res.sendFile(realPath, {
      dotfiles: 'deny', // Prevent access to hidden files
      headers: {
        'X-Content-Type-Options': 'nosniff',
        'Content-Disposition': `attachment; filename="${sanitized}"`
      }
    });

  } catch (error) {
    console.error('File access error:', error);
    // Generic error message to prevent information disclosure
    res.status(500).json({ error: 'Unable to process request' });
  }
});
```

